<?php if(!hasPermission('accounting_create')){http_response_code(403); include __DIR__.'/../errors/403.php'; return;} $db=Database::connection(); $errs=[]; if($_SERVER['REQUEST_METHOD']==='POST'){ $rows=$_POST['rows']??[]; $dr=0;$cr=0; foreach($rows as $r){$dr+=(float)$r['dr'];$cr+=(float)$r['cr'];} if(abs($dr-$cr)>0.001)$errs[]='Total Debit MUST equal Total Credit'; if(!$errs){$db->beginTransaction(); try{$no=generateInvoiceNo('JV',getFinancialYear());$db->prepare('INSERT INTO vouchers (voucher_no,voucher_date,voucher_type,narration,total_debit,total_credit,financial_year,created_by,created_at) VALUES (?,?,?,?,?,?,?,?,NOW())')->execute([$no,$_POST['voucher_date'],$_POST['voucher_type'],$_POST['narration'],$dr,$cr,getFinancialYear($_POST['voucher_date']),getCurrentUser()['id']??null]);$vid=$db->lastInsertId();$e=$db->prepare('INSERT INTO voucher_entries (voucher_id,account_id,debit_amount,credit_amount,narration) VALUES (?,?,?,?,?)');foreach($rows as $r){$e->execute([$vid,$r['account_id'],$r['dr'],$r['cr'],$r['narration']??'']);}$db->commit();redirect('accounting/voucher-list');}catch(Throwable $x){$db->rollBack();$errs[]=$x->getMessage();}} } ?><form method='post'><?=csrfField()?><?php foreach($errs as $e) echo '<div>'.$e.'</div>';?><input type='date' name='voucher_date' value='<?=date('Y-m-d')?>'><input name='voucher_type' value='journal'><input name='narration'><input name='rows[0][account_id]'><input name='rows[0][dr]' value='0'><input name='rows[0][cr]' value='0'><button>Save</button></form>
